// Step 1: Safely get incoming data
const input = $input.first().json || $input.first().json.body || {};

// Step 2: Extract fields with fallback
const title = input.title?.trim() || "";
const content = input.content?.trim() || "";
const category = input.category?.trim() || "general";
const lang = input.lang?.trim() || "en";

// Step 3: Validate required fields
if (!title || !content) {
  return [{
    json: {
      success: false,
      error: "Missing title or content",
      rawInput: input
    }
  }];
}

// Step 4: Pass to next node
return [{
  json: {
    title,
    content,
    category,
    lang
  }
}];

